var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"요원님! 중대원 전원 관측소에서 퇴각했습니다!","JPN":"ご報告します！　中隊員全員、観測所から退却しました！","ENG":"Sir, all units have evacuated the Observation Post.","TWN":"要員！全體成員都從觀測站撤退了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"좋아. 늙은이가 솜씨 발휘할 시간이군.","JPN":"よし。ここからは老兵の腕の見せ所だな。","ENG":"Fine. It's time that this old salt got to work.","TWN":"好，到了老頭子施展本領的時候了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"세상에. 관측소를 통째로 무너뜨리셨군요.","JPN":"なんと……観測所を丸ごと破壊したんですね。","ENG":"Good Lord. You blew up the entire building.","TWN":"天啊，整個觀測站全被炸個粉碎了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"저렇게 많은 폭약을 언제 매설해 두신 겁니까?","JPN":"あんな大量の爆薬をいつの間に設置したんですか？","ENG":"When did you have time to set up so many explosives?","TWN":"您是什麼時候埋下這麼多炸藥的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"영업 비밀일세. 늙은 개도 숨겨둔 재주 하나쯤은 있는 법이지.","JPN":"企業秘密だ。年老いた犬にも一つくらい特技があるものだからな。","ENG":"It's a trade secret. Let's say it's one of the tricks that this old dog can still pull off.","TWN":"這是商業機密。老狗也會有幾招把戲嘛。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그보다 다른 대원들은 모두 무사한가?","JPN":"それより、他の隊員たちは全員無事か？","ENG":"How are the squad members doing?","TWN":"比起這個，其他隊員都沒事吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"부상자가 많습니다. 요원님께서 놈들의 시선을 끌어 주시지 않았더라면 전멸했을 겁니다.","JPN":"負傷者が多数発生しています。あなたが奴らの気を引いてくれなければ、全滅も免れなかったでしょう。","ENG":"A lot of them are wounded. We would have been annihilated if it weren't for you, sir.","TWN":"有很多負傷者。如果不是要員引開那些傢伙，我們就全滅了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"피해가 크군. 당분간 관측소를 다시 설치하는 건 어렵겠어.","JPN":"被害が大きいな。しばらくは観測所の再設置も難しいだろう。","ENG":"This is not good. We won't be able to get the Observation Post up running again anytime soon.","TWN":"損失慘重啊。看來短時間內很難重新設置觀測站了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데...... 아까 그것들도 침식체입니까?","JPN":"ところで……さっきのアレも侵食体なんですか？","ENG":"So... were those things C.O.s as well?","TWN":"不過……剛才那些傢伙是侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"그 동안 다이브를 수도 없이 해 봤지만...... 저런 소름 끼치는 것들은 난생 처음입니다.","JPN":"今までダイブは何度も経験していますが……あんな不気味なモノは生まれて初めて見ましたよ。","ENG":"I've done my share of Dives, but I've never run into such creepy things in my whole life.","TWN":"這段時間我躍入了無數次了…… 但那種可怕的東西還是我有生以來第一次看到。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"운이 좋았군. 앞으로도 마주칠 일 없기를 바라겠네.","JPN":"運が良かったんだな。これからも出くわさないことを祈ってるぞ。","ENG":"Then you've been lucky. Pray that you won't run into them again.","TWN":"運氣可真好啊。希望你以後不會再遇到這種事情了呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"부상자들을 챙기게. 나는 상부에 이 사실을 알려야겠어.","JPN":"負傷者たちを頼む。俺はこの件を上に報告しないと。","ENG":"Go attend the injured, Commander. I'm going to have a talk with the Institution about this.","TWN":"去照顧傷患吧。我得去跟上級報告才行。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"자네가 직접 연락하다니, 아무래도 상황이 생각보다 더 안 좋은 모양이군.","JPN":"あなたの方から連絡してくるとは、どうやら状況がさらに悪化したようですね。","ENG":"You're doing the report yourself. The situation must be worse than we expected.","TWN":"你竟然會直接聯絡我，看來情況比預想得還要糟糕啊。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"언제는 안 그랬던 것처럼 말하는군.","JPN":"状況が良かった頃があったかのような口ぶりだな。","ENG":"When isn't it?","TWN":"哪次不是這樣呢。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>오래된 목소리</color>의 경고대로야. 맥크레디 포인트가 활성화 될 징조를 보이고 있어.","JPN":"<color=#ffd34c>古き声</color>の警告通りだ。マクレディーポイントが活性化する兆候を示してる。","ENG":"It's just as the <color=#ffd34c>Old Voice</color> warned us. There are signs that MacCready Point is about to become active.","TWN":"正如<color=#ffd34c>老聲音</color>的警告，麥克蕾蒂要點出現了活性化的跡象。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"관측소 친구들은 멋모르고 있다가 그 안으로 빨려 들어간 것 같군.","JPN":"観測所の奴らは何も知らないまま、あの中に吸い込まれたらしい。","ENG":"It looks like the people here at the Observation Post were caught unaware and swept away.","TWN":"觀測站的朋友們大概是在不知道的情況下，被吸進去了吧。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};